+        /// <summary>
+        /// Builds the APIM URL for the general help landing page (no context ID).
+        /// Per the APIM spec, the no-context-ID format uses only {product}, not {product}:{version}.
+        /// </summary>
+        /// <example>
+        /// <code>
+        /// // Enterprise, English:
+        /// // https://apim.viewpointplatform.com/help/v1/contents/urn:contentId::projectsight
+        ///
+        /// // GO, French:
+        /// // https://apim.viewpointplatform.com/help/v1/contents/urn:contentId:_GO:projectsight:fr
+        /// </code>
+        /// </example>
+        /// <param name="baseUrl">The APIM base URL from ExternalService (e.g., https://apim.viewpointplatform.com/help/v1/contents)</param>
+        /// <param name="accountType">The user's account type (Enterprise, GO, Disrupt)</param>
+        /// <param name="languageId">The user's preferred language ID</param>
+        /// <returns>The landing page URL without a topic ID, or empty string if baseUrl is null/empty</returns>
+        public static string BuildOnlineHelpLandingUrl(string baseUrl, Account.AccountTypes? accountType, int languageId)
+        {
+            if (string.IsNullOrWhiteSpace(baseUrl))
+            {
+                return string.Empty;
+            }
+
+            baseUrl = baseUrl.TrimEnd('/');
+            var suffix = GetAccountSuffix(accountType);
+            var locale = GetApimLocale(languageId, accountType);
+            var localePart = string.IsNullOrEmpty(locale) ? "" : $":{locale}";
+
+            return $"{baseUrl}/urn:contentId:{suffix}:{APIM_PRODUCT}{localePart}";
+        }
+
